namespace CourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public int DepartmentId { get; set; }
    public string DepartmentCode { get; set; } = string.Empty;
    public string CourseNumber { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }

    public string FullCode => $"{DepartmentCode} {CourseNumber}";
}

public class EnrollmentRequest
{
    public string StudentName { get; set; } = string.Empty;
    public string StudentId { get; set; } = string.Empty;
    public int CourseId { get; set; }
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and their impact on the present." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "101", Title = "Introduction to Programming", Description = "Fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published research on CS pedagogy.", IsFeatured = true },
            new() { Id = 2, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "201", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques.", Credits = 4, Schedule = "TTh 10:30–11:50 AM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm optimization and has contributed to several open-source projects.", IsFeatured = true },
            new() { Id = 3, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "350", Title = "Database Systems", Description = "Relational database design, SQL, transaction processing, and introduction to NoSQL systems.", Credits = 3, Schedule = "MWF 1:00–1:50 PM", InstructorName = "Dr. Maria Rodriguez", InstructorBio = "Dr. Rodriguez worked in industry for 10 years at major tech companies before joining academia." },
            new() { Id = 4, DepartmentId = 1, DepartmentCode = "CS", CourseNumber = "410", Title = "Machine Learning", Description = "Supervised and unsupervised learning, neural networks, and practical applications of ML.", Credits = 4, Schedule = "TTh 2:00–3:20 PM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published research on CS pedagogy.", IsFeatured = true },
            new() { Id = 5, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions with applications.", Credits = 4, Schedule = "MWF 8:00–8:50 AM", InstructorName = "Dr. Robert Liu", InstructorBio = "Dr. Liu is a renowned mathematician who has authored three widely-used calculus textbooks.", IsFeatured = true },
            new() { Id = 6, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, and eigenvalues.", Credits = 3, Schedule = "TTh 9:00–10:20 AM", InstructorName = "Dr. Robert Liu", InstructorBio = "Dr. Liu is a renowned mathematician who has authored three widely-used calculus textbooks." },
            new() { Id = 7, DepartmentId = 2, DepartmentCode = "MATH", CourseNumber = "301", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression.", Credits = 3, Schedule = "MWF 11:00–11:50 AM", InstructorName = "Dr. Anna Petrov", InstructorBio = "Dr. Petrov's research focuses on applied statistics in biomedical sciences." },
            new() { Id = 8, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introduction to physics.", Credits = 4, Schedule = "MWF 10:00–10:50 AM, Lab F 2:00–4:00 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is an experimental physicist with expertise in condensed matter physics.", IsFeatured = true },
            new() { Id = 9, DepartmentId = 3, DepartmentCode = "PHYS", CourseNumber = "201", Title = "General Physics II", Description = "Electricity, magnetism, optics, and modern physics.", Credits = 4, Schedule = "MWF 10:00–10:50 AM, Lab W 2:00–4:00 PM", InstructorName = "Dr. Michael Torres", InstructorBio = "Dr. Torres is an experimental physicist with expertise in condensed matter physics." },
            new() { Id = 10, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "101", Title = "Composition and Rhetoric", Description = "Developing clear, effective academic writing through essay assignments and peer review.", Credits = 3, Schedule = "MWF 9:00–9:50 AM", InstructorName = "Prof. Diana Walsh", InstructorBio = "Prof. Walsh is an award-winning author and writing instructor with over 20 years of teaching experience." },
            new() { Id = 11, DepartmentId = 4, DepartmentCode = "ENG", CourseNumber = "250", Title = "American Literature", Description = "Survey of major American literary works from the colonial period to the present.", Credits = 3, Schedule = "TTh 1:00–2:20 PM", InstructorName = "Prof. Diana Walsh", InstructorBio = "Prof. Walsh is an award-winning author and writing instructor with over 20 years of teaching experience." },
            new() { Id = 12, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "101", Title = "World History I", Description = "Survey of world civilizations from prehistory to 1500 CE.", Credits = 3, Schedule = "TTh 11:00 AM–12:20 PM", InstructorName = "Dr. Kevin Okafor", InstructorBio = "Dr. Okafor specializes in comparative world history and has conducted fieldwork across three continents." },
            new() { Id = 13, DepartmentId = 5, DepartmentCode = "HIST", CourseNumber = "205", Title = "Modern European History", Description = "Europe from the Enlightenment through the 20th century, covering revolutions, wars, and cultural change.", Credits = 3, Schedule = "MWF 2:00–2:50 PM", InstructorName = "Dr. Kevin Okafor", InstructorBio = "Dr. Okafor specializes in comparative world history and has conducted fieldwork across three continents.", IsFeatured = true }
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.FullCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real app, this would persist to a database
        return !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId)
            && request.CourseId > 0
            && _courses.Any(c => c.Id == request.CourseId);
    }
}

