@page "/courses"
@inject CatalogService Catalog

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search by title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Code &mdash; @dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <p class="text-muted">No courses match your search criteria.</p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th>Schedule</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.FullCode</td>
                    <td>@course.Title</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td>@course.Schedule</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery]
    public string? Search { get; set; }

    [SupplyParameterFromQuery]
    public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

@page "/enroll"
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Submit this form to request enrollment in a course. You will be notified by email once your request is processed.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4>Request Submitted</h4>
        <p>Your enrollment request has been received. You will receive a confirmation email shortly.</p>
        <a href="courses" class="btn btn-primary">Browse More Courses</a>
    </div>
}
else
{
    if (validationError is not null)
    {
        <div class="alert alert-danger">@validationError</div>
    }

    <form method="post" action="enroll" class="col-md-6">
        <AntiforgeryToken />

        <div class="mb-3">
            <label for="studentName" class="form-label">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" class="form-control" required />
        </div>

        <div class="mb-3">
            <label for="studentId" class="form-label">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" class="form-control" required placeholder="e.g., S12345678" />
        </div>

        <div class="mb-3">
            <label for="courseId" class="form-label">Course</label>
            <select id="courseId" name="Model.CourseId" class="form-select" required>
                <option value="">-- Select a course --</option>
                @foreach (var course in courses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.FullCode &mdash; @course.Title</option>
                }
            </select>
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm]
    public EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery]
    public int? CourseId { get; set; }

    private List<Course> courses = new();
    private bool submitted;
    private string? validationError;

    protected override void OnInitialized()
    {
        courses = Catalog.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }

        // Check if this is a POST (form submission)
        if (!string.IsNullOrWhiteSpace(Model.StudentName) || !string.IsNullOrWhiteSpace(Model.StudentId))
        {
            HandleSubmit();
        }
    }

    private void HandleSubmit()
    {
        if (string.IsNullOrWhiteSpace(Model.StudentName))
        {
            validationError = "Please enter your full name.";
            return;
        }

        if (string.IsNullOrWhiteSpace(Model.StudentId))
        {
            validationError = "Please enter your student ID.";
            return;
        }

        if (Model.CourseId <= 0)
        {
            validationError = "Please select a course.";
            return;
        }

        if (Catalog.SubmitEnrollmentRequest(Model))
        {
            submitted = true;
        }
        else
        {
            validationError = "Unable to process your request. Please verify your information and try again.";
        }
    }
}

